begin;
create table public.anki_reviewers(id uuid primary key default gen_random_uuid(),user_id uuid not null unique references auth.users(id) on delete restrict,reviewer_status text not null default 'pending',roles text[] not null default '{}',display_name text not null,qualification_type text null,qualification_verified boolean not null default false,qualification_metadata jsonb not null default '{}',is_active boolean not null default false,revoked_at timestamptz null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),safe_metadata jsonb not null default '{}',constraint anki_reviewers_status check(reviewer_status in('pending','active','suspended','revoked')),constraint anki_reviewers_roles check(roles<@array['mapping_reviewer','clinical_editor','deck_editor','release_manager','administrator']::text[]),constraint anki_reviewers_safe check(public.educational_metadata_is_safe(qualification_metadata) and public.educational_metadata_is_safe(safe_metadata)));
create table public.anki_review_assignments(id uuid primary key,factory_run_id uuid not null references public.anki_kg_factory_runs(id) on delete restrict,factory_batch_id uuid not null references public.anki_kg_factory_batches(id) on delete restrict,deck_release_id uuid not null references public.anki_deck_releases(id) on delete restrict,input_manifest_checksum text not null,assigned_reviewer_id uuid not null references public.anki_reviewers(id) on delete restrict,assignment_type text not null default 'mapping_calibration',status text not null default 'draft',due_at timestamptz null,created_at timestamptz not null default now(),started_at timestamptz null,submitted_at timestamptz null,completed_at timestamptz null,supersedes_assignment_id uuid null references public.anki_review_assignments(id) on delete restrict,safe_metadata jsonb not null default '{}',constraint anki_review_assignments_hash check(input_manifest_checksum~'^[a-f0-9]{64}$'),constraint anki_review_assignments_status check(status in('draft','assigned','in_progress','submitted','completed','cancelled','superseded')),constraint anki_review_assignments_safe check(public.educational_metadata_is_safe(safe_metadata)));
create table public.anki_review_assignment_items(id uuid primary key,assignment_id uuid not null references public.anki_review_assignments(id) on delete restrict,canonical_card_id uuid not null references public.canonical_cards(id) on delete restrict,canonical_card_version_id uuid not null references public.canonical_card_versions(id) on delete restrict,base_content_hash text not null,note_guid text not null,card_ordinal integer not null,deck_path text not null,factory_terminal_queue text not null,risk_tier text not null,proposed_entity_ids uuid[] not null default '{}',proposed_mapping_roles text[] not null default '{}',machine_consensus text not null,critic_flags text[] not null default '{}',competing_candidate_ids uuid[] not null default '{}',evidence_hashes text[] not null default '{}',required_human_action text not null,item_status text not null default 'pending',sort_order integer not null,created_at timestamptz not null default now(),constraint anki_review_items_hash check(base_content_hash~'^[a-f0-9]{64}$'),constraint anki_review_items_ordinal check(card_ordinal>=0),constraint anki_review_items_risk check(risk_tier in('A','B','C','D')),constraint anki_review_items_status check(item_status in('pending','in_review','decision_saved','change_proposed','submitted','conflict','skipped','superseded')),constraint anki_review_items_card_unique unique(assignment_id,canonical_card_id,canonical_card_version_id),constraint anki_review_items_identity_unique unique(assignment_id,note_guid,card_ordinal),constraint anki_review_items_order_unique unique(assignment_id,sort_order));
create table public.anki_mapping_review_submissions(id uuid primary key default gen_random_uuid(),assignment_id uuid not null references public.anki_review_assignments(id) on delete restrict,assignment_item_id uuid not null references public.anki_review_assignment_items(id) on delete restrict,reviewer_user_id uuid not null references auth.users(id) on delete restrict,canonical_card_id uuid not null references public.canonical_cards(id) on delete restrict,canonical_card_version_id uuid not null references public.canonical_card_versions(id) on delete restrict,base_content_hash text not null,canonical_entity_id uuid null references public.canonical_entities(id) on delete restrict,mapping_role text null,human_decision text not null,human_confidence numeric(5,4) not null,no_mapping_classification text null,ambiguity_resolution text not null,safe_reason_codes text[] not null default '{}',safe_notes text not null default '',reviewer_qualification_snapshot jsonb not null,provenance_method text not null default 'direct_human_review',evidence_hashes text[] not null,idempotency_key uuid not null,client_version text not null,submitted_at timestamptz not null default now(),supersedes_submission_id uuid null references public.anki_mapping_review_submissions(id) on delete restrict,constraint anki_mapping_review_hash check(base_content_hash~'^[a-f0-9]{64}$'),constraint anki_mapping_review_decision check(human_decision in('approved','rejected','needs_changes','defer')),constraint anki_mapping_review_confidence check(human_confidence between 0 and 1),constraint anki_mapping_review_role check(mapping_role is null or mapping_role in('teaches','tests','explains','demonstrates','context_only','broadly_related')),constraint anki_mapping_review_nomap check((canonical_entity_id is not null and mapping_role is not null and no_mapping_classification is null)or(canonical_entity_id is null and mapping_role is null and no_mapping_classification in('correctly_unmapped','missing_alias','missing_canonical_entity','extraction_failure','threshold_too_conservative','nonclinical_or_low_value','multiconcept_or_ambiguous','deck_improvement_required'))),constraint anki_mapping_review_provenance check(provenance_method='direct_human_review'),constraint anki_mapping_review_safe check(public.educational_metadata_is_safe(reviewer_qualification_snapshot)and char_length(safe_notes)<=1000),constraint anki_mapping_review_idempotent unique(reviewer_user_id,idempotency_key));
create table public.anki_card_change_proposals(id uuid primary key default gen_random_uuid(),assignment_id uuid not null references public.anki_review_assignments(id) on delete restrict,assignment_item_id uuid not null references public.anki_review_assignment_items(id) on delete restrict,reviewer_user_id uuid not null references auth.users(id) on delete restrict,canonical_card_id uuid not null references public.canonical_cards(id) on delete restrict,base_canonical_card_version_id uuid not null references public.canonical_card_versions(id) on delete restrict,base_content_hash text not null,status text not null,change_type text not null,reason_codes text[] not null default '{}',client_version text not null,idempotency_key uuid not null,created_at timestamptz not null default now(),submitted_at timestamptz null,reviewed_at timestamptz null,supersedes_proposal_id uuid null references public.anki_card_change_proposals(id) on delete restrict,replaced_by_proposal_id uuid null references public.anki_card_change_proposals(id) on delete restrict,constraint anki_card_change_status check(status in('draft','submitted','under_review','changes_requested','approved_for_incorporation','rejected','withdrawn','superseded','incorporated')),constraint anki_card_change_type check(change_type in('content_edit','tag_edit','deck_path_proposal','split_card_proposal','merge_card_proposal','retire_card_proposal','duplicate_report','clinical_correction','formatting_correction')),constraint anki_card_change_idempotent unique(reviewer_user_id,idempotency_key));
create table public.anki_card_change_proposal_revisions(id uuid primary key default gen_random_uuid(),proposal_id uuid not null references public.anki_card_change_proposals(id) on delete restrict,revision_number integer not null,base_canonical_card_version_id uuid not null references public.canonical_card_versions(id) on delete restrict,base_content_hash text not null,edited_fields jsonb not null,tag_changes jsonb not null default '{}',proposed_deck_path text null,new_computed_content_hash text not null,reviewer_notes text not null default '',reason_codes text[] not null default '{}',created_at timestamptz not null default now(),constraint anki_card_revision_number check(revision_number>0),constraint anki_card_revision_hashes check(base_content_hash~'^[a-f0-9]{64}$' and new_computed_content_hash~'^[a-f0-9]{64}$'),constraint anki_card_revision_fields check(jsonb_typeof(edited_fields)='array' and public.educational_metadata_is_safe(tag_changes) and char_length(reviewer_notes)<=1000),constraint anki_card_revision_unique unique(proposal_id,revision_number));
create table public.anki_reviewer_audit_events(id uuid primary key default gen_random_uuid(),reviewer_user_id uuid not null references auth.users(id) on delete restrict,device_token_id uuid null references public.brobot_anki_device_tokens(id) on delete restrict,assignment_id uuid null references public.anki_review_assignments(id) on delete restrict,assignment_item_id uuid null references public.anki_review_assignment_items(id) on delete restrict,mapping_submission_id uuid null references public.anki_mapping_review_submissions(id) on delete restrict,change_proposal_id uuid null references public.anki_card_change_proposals(id) on delete restrict,event_type text not null,request_id uuid not null,addon_version text not null,event_at timestamptz not null default now(),reason_codes text[] not null default '{}',safe_metadata jsonb not null default '{}',constraint anki_reviewer_audit_event check(event_type in('assignment_downloaded','item_opened','mapping_decision_saved','change_draft_saved','submission_attempted','submission_accepted','submission_rejected','conflict_detected','assignment_submitted','device_revoked')),constraint anki_reviewer_audit_safe check(public.educational_metadata_is_safe(safe_metadata)));
create function public.guard_anki_reviewer_immutable()returns trigger language plpgsql as $$begin raise exception 'submitted reviewer records are immutable';end$$;create trigger guard_submitted_mapping_review before update or delete on public.anki_mapping_review_submissions for each row execute function public.guard_anki_reviewer_immutable();create trigger guard_submitted_change_revision before update or delete on public.anki_card_change_proposal_revisions for each row execute function public.guard_anki_reviewer_immutable();
create function public.guard_submitted_anki_review_item()returns trigger language plpgsql as $$begin if old.item_status in('submitted','superseded')then raise exception 'submitted assignment items are immutable';end if;return new;end$$;create trigger guard_submitted_anki_review_item before update or delete on public.anki_review_assignment_items for each row execute function public.guard_submitted_anki_review_item();
create function public.validate_anki_review_item()returns trigger language plpgsql as $$declare ok boolean;begin select exists(select 1 from public.canonical_card_versions v join public.anki_deck_release_cards rc on rc.canonical_card_id=new.canonical_card_id and rc.canonical_card_version_id=v.id join public.anki_review_assignments a on a.id=new.assignment_id and a.deck_release_id=rc.deck_release_id where v.id=new.canonical_card_version_id and v.canonical_card_id=new.canonical_card_id and v.content_hash=new.base_content_hash)into ok;if not ok then raise exception 'assignment item card/version/release mismatch';end if;return new;end$$;create trigger validate_anki_review_item before insert or update on public.anki_review_assignment_items for each row execute function public.validate_anki_review_item();
do $$declare t text;begin foreach t in array array['anki_reviewers','anki_review_assignments','anki_review_assignment_items','anki_mapping_review_submissions','anki_card_change_proposals','anki_card_change_proposal_revisions','anki_reviewer_audit_events']loop execute format('alter table public.%I enable row level security',t);execute format('alter table public.%I force row level security',t);execute format('revoke all on public.%I from anon,authenticated,service_role',t);execute format('grant select,insert,update,delete on public.%I to service_role',t);end loop;end$$;
comment on table public.anki_mapping_review_submissions is 'Direct human submissions awaiting separate adjudication; never published mappings.';comment on table public.anki_card_change_proposal_revisions is 'SnapOrtho-controlled editorial content; excluded from logs, telemetry, and audit metadata.';
commit;
